class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            for j in range(1, i + 1):
                if s[i - j:i] != '0' and int(s[i - j:i]) <= k:
                    dp[i] = (dp[i] + dp[i - j]) % MOD
        return dp[n]
